/**
 * n8n Code Node (JavaScript)
 * Externes Modul: cheerio
 * Eingaben (nach Priorität):
 *  1) $input.first().json.data   -> HTML vom vorherigen Node (z. B. HTTP Request)
 *  2) items[0].json.html         -> bereits geliefertes HTML
 *  3) items[0].json.url          -> URL, wird hier per fetch geladen
 * Ausgabe:
 *  - title, description, text (gesäubert), url (best guess)
 */

const cheerio = require('cheerio');

function safeGetInputHtml() {
  try {
    const html = $input.first()?.json?.data;
    if (typeof html === 'string' && html.trim()) return html;
  } catch (_) {}
  return null;
}

function candidateUrlFromInputs(item) {
  if (item?.json?.url) return item.json.url;
  try {
    const prevUrl = $input.first()?.json?.url;
    if (typeof prevUrl === 'string' && prevUrl.trim()) return prevUrl;
  } catch (_) {}
  return null;
}

async function getHtmlAndBase(item) {
  const htmlFromInput = safeGetInputHtml();
  if (htmlFromInput) return { html: htmlFromInput, baseHint: candidateUrlFromInputs(item) };

  if (item?.json?.html && typeof item.json.html === 'string') {
    return { html: item.json.html, baseHint: candidateUrlFromInputs(item) };
  }

  const url = item?.json?.url;
  if (!url) {
    throw new Error('Keine HTML-Quelle gefunden. Bitte übergib entweder $input.first().json.data, items[0].json.html oder items[0].json.url.');
  }
  const res = await fetch(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0 Safari/537.36',
      'Accept-Language': 'de,en;q=0.9',
      'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8'
    }
  });
  if (!res.ok) throw new Error(`Fehler beim Laden (${res.status} ${res.statusText}) für URL: ${url}`);
  const html = await res.text();
  return { html, baseHint: url };
}

function pickBestUrl($, baseHint) {
  const canonical = $('link[rel="canonical"]').attr('href') || '';
  const ogUrl = $('meta[property="og:url"]').attr('content') || '';
  const baseHref = $('base').attr('href') || '';
  return baseHint || canonical || ogUrl || baseHref || null;
}

function extractMainText(html, baseUrl) {
  const $ = cheerio.load(html);

  $('script, style, noscript, svg, canvas, iframe, video, audio, picture, source').remove();
  $('header, footer, nav, aside, form, input, button, select, textarea').remove();

  $('[role="navigation"], [role="banner"], [role="contentinfo"]').remove();
  $('[class*="cookie"], [id*="cookie"], [class*="banner"], [class*="subscribe"], [class*="newsletter"]').remove();

  let main = $('main');
  if (!main.length) {
    const candidates = [
      '[role="main"]',
      'article',
      '.content, #content, .post, #post, .entry-content, .article-content, .rich-text'
    ];
    for (const sel of candidates) {
      const node = $(sel).first();
      if (node.length) { main = node; break; }
    }
  }
  if (!main.length) main = $('body');

  const rawText = main.text() || '';
  const text = rawText.replace(/\s+/g, ' ').trim();

  const title = ($('title').first().text() || '').trim();
  const description = ($('meta[name="description"]').attr('content') || '').trim();

  const bestUrl = pickBestUrl($, baseUrl);

  return {
    url: bestUrl,
    title,
    description,
    text
  };
}

const item = items[0] || { json: {} };
const { html, baseHint } = await getHtmlAndBase(item);
const result = extractMainText(html, baseHint);

return [{ json: result }];

