/**
 * n8n Code Node (JavaScript)
 * Input: $input.first().json.website
 * Output: { website, impressumUrl }
 */

const website = $input.first().json.website || "";

let impressumUrl = null;

if (website.endsWith("/")) {
  impressumUrl = website + "impressum";
} else {
  impressumUrl = website + "/impressum";
}

return [
  {
    json: {
      website,
      impressumUrl
    }
  }
];

const inputs = $input.all();

let result = {
  url: null,
  website_html: null,
  impressum_html: null,
};

// Durch alle Inputs iterieren
for (const input of inputs) {
  const sourceUrl = input.json.url || "";
  const html = input.json.data || "";

  if (sourceUrl.includes("impressum")) {
    result.impressum_html = html;
  } else {
    result.url = sourceUrl;
    result.website_html = html;
  }
}

return [{ json: result }];

